#include <stdio.h>
int minPathSum(int** grid, int gridSize, int* gridColSize) {
    int m = gridSize;
    int n = gridColSize[0];
    for (int i = m - 1; i >= 0; i--) {
        for (int j = n - 1; j >= 0; j--) {
            if (i == m - 1 && j == n - 1) continue;
            if (i == m - 1) grid[i][j] += grid[i][j + 1];
            else if (j == n - 1) grid[i][j] += grid[i + 1][j];
            else grid[i][j] += (grid[i + 1][j] < grid[i][j + 1] ? grid[i + 1][j] : grid[i][j + 1]);
        }
    }
    return grid[0][0];
}

