        for i in range(m - 1, -1, -1):
            for j in range(n - 1, -1, -1):
                if i == m - 1 and j == n - 1: continue
                if i == m - 1: grid[i][j] += grid[i][j + 1]
                elif j == n - 1: grid[i][j] += grid[i + 1][j]
                else: grid[i][j] += min(grid[i + 1][j], grid[i][j + 1])
        return grid[0][0]

